                when (uri.pathSegments.firstOrNull()) {
                    "confirm" -> {
                        startActivity(
                            Intent(this, PaymentConfirmActivity::class.java).apply {
                                addFlags(Intent.FLAG_ACTIVITY_CLEAR_TOP or Intent.FLAG_ACTIVITY_SINGLE_TOP)
                            }
                        )
                    }
